Future<T> retry<T>(Future<T> Function() action, {int maxAttempts = 3}) async {
  var attempt = 0;
  while (true) {
    try {
      return await action();
    } catch (e) {
      attempt++;
      if (attempt >= maxAttempts) rethrow;
      await Future.delayed(Duration(seconds: 1 << attempt));
    }
  }
}

