class QueueFromStacks<T> {
  final _inStack = <T>[];
  final _outStack = <T>[];

  void enqueue(T item) => _inStack.add(item);

  T dequeue() {
    if (_outStack.isEmpty) {
      while (_inStack.isNotEmpty) _outStack.add(_inStack.removeLast());
    }
    return _outStack.removeLast();
  }
}

class BSTNode {
